template<typename T>
void verify(const T* ref_out, const T* out, int64_t n)
{
  int error = std::memcmp(ref_out, out, n * sizeof(T));
  if (error) {
    for (int64_t i = 0; i < n; i++) {
      if (ref_out[i] != out[i]) {
        std::printf("@%zu: %lf != %lf\n", (size_t)i, (double)ref_out[i], (double)out[i]);
        break;
      }
    }
  }
  std::printf("%s\n", error ? "FAIL" : "PASS");
}

template<typename T, int N>
__global__ void scan_with_bank_conflicts_kernel(const T* in, T* out)
{
  __shared__ T temp[N];

  int thid = threadIdx.x;
  int64_t bid = (int64_t)blockIdx.x;

  const T* t_in = in + bid * N;
  T* t_out = out + bid * N;

  int offset = 1;

  temp[2 * thid]     = t_in[2 * thid];
  temp[2 * thid + 1] = t_in[2 * thid + 1];

  for (int d = N >> 1; d > 0; d >>= 1) {
    __syncthreads();
    if (thid < d) {
      int ai = offset * (2 * thid + 1) - 1;
      int bi = offset * (2 * thid + 2) - 1;
      temp[bi] += temp[ai];
    }
    offset *= 2;
  }

  __syncthreads();
  if (thid == 0) temp[N - 1] = 0;

  for (int d = 1; d < N; d *= 2) {
    offset >>= 1;
    __syncthreads();
    if (thid < d) {
      int ai = offset * (2 * thid + 1) - 1;
      int bi = offset * (2 * thid + 2) - 1;
      T t = temp[ai];
      temp[ai] = temp[bi];
      temp[bi] += t;
    }
  }

  __syncthreads();
  t_out[2 * thid]     = temp[2 * thid];
  t_out[2 * thid + 1] = temp[2 * thid + 1];
}

