template<typename T, int N>
void runTest(const int64_t n, const int repeat, bool timing = false)
{
  int64_t num_blocks = (n + N - 1) / N;
  int64_t nelems = num_blocks * N;
  size_t bytes = (size_t)nelems * sizeof(T);

  T* in = (T*)std::malloc(bytes);
  T* out = (T*)std::malloc(bytes);
  T* ref_out = (T*)std::malloc(bytes);

  std::srand(123);
  for (int64_t i = 0; i < nelems; i++) in[i] = (T)(std::rand() % 5 + 1);

  T* t_in = in;
  T* t_out = ref_out;
  for (int64_t blk = 0; blk < num_blocks; blk++) {
    t_out[0] = 0;
    for (int i = 1; i < N; i++)
      t_out[i] = t_out[i - 1] + t_in[i - 1];
    t_out += N;
    t_in += N;
  }

  T *d_in = nullptr, *d_out = nullptr;
  CUDA_CHECK(cudaMalloc((void**)&d_in, bytes));
  CUDA_CHECK(cudaMalloc((void**)&d_out, bytes));
  CUDA_CHECK(cudaMemcpy(d_in, in, bytes, cudaMemcpyHostToDevice));

  dim3 block(N / 2);
  dim3 grid((unsigned int)num_blocks);

  auto start = std::chrono::steady_clock::now();
  for (int i = 0; i < repeat; i++) {
    scan_with_bank_conflicts_kernel<T, N><<<grid, block>>>(d_in, d_out);
  }
  CUDA_CHECK(cudaGetLastError());
  CUDA_CHECK(cudaDeviceSynchronize());
  auto end = std::chrono::steady_clock::now();

  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  if (timing) {
    std::printf("Element size in bytes is %zu. Average execution time of scan (w/  bank conflicts): %f (us)\n",
                sizeof(T), (time * 1e-3f) / repeat);
  }

  CUDA_CHECK(cudaMemcpy(out, d_out, bytes, cudaMemcpyDeviceToHost));
  if (!timing) verify(ref_out, out, nelems);

  start = std::chrono::steady_clock::now();
  for (int i = 0; i < repeat; i++) {
    scan_without_bank_conflicts_kernel<T, N><<<grid, block>>>(d_in, d_out);
  }
  CUDA_CHECK(cudaGetLastError());
  CUDA_CHECK(cudaDeviceSynchronize());
  end = std::chrono::steady_clock::now();

  auto bcao_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  if (timing) {
    std::printf("Element size in bytes is %zu. Average execution time of scan (w/o bank conflicts): %f (us). ",
                sizeof(T), (bcao_time * 1e-3f) / repeat);
    std::printf("Reduce the time by %.1f%%\n", (time - bcao_time) * 1.0 / time * 100);
  }

  CUDA_CHECK(cudaMemcpy(out, d_out, bytes, cudaMemcpyDeviceToHost));
  if (!timing) verify(ref_out, out, nelems);

  CUDA_CHECK(cudaFree(d_in));
  CUDA_CHECK(cudaFree(d_out));
  std::free(in);
  std::free(out);
  std::free(ref_out);
}

template<int N>
void run(const int n, const int repeat)
{
  for (int i = 0; i < 2; i++) {
    bool report_timing = i > 0;
    std::printf("\nThe number of elements to scan in a thread block: %d\n", N);
    runTest< char, N>(n, repeat, report_timing);
    runTest<short, N>(n, repeat, report_timing);
    runTest<  int, N>(n, repeat, report_timing);
    runTest< long, N>(n, repeat, report_timing);
  }
}

int main(int argc, char* argv[])
{
  if (argc != 3) {
    std::printf("Usage: %s <number of elements> <repeat>\n", argv[0]);
    return 1;
  }

  const int n = std::atoi(argv[1]);
  const int repeat = std::atoi(argv[2]);

  run< 128>(n, repeat);
  run< 256>(n, repeat);
  run< 512>(n, repeat);
  run<1024>(n, repeat);
  run<2048>(n, repeat);

  return 0;
}

