    cuda_check(cudaMemcpy(out, d_out, (size_t)bytes, cudaMemcpyDeviceToHost));
  }
  if (!timing) verify(ref_out, out, nelems);

  if (d_in) cuda_check(cudaFree(d_in));
  if (d_out) cuda_check(cudaFree(d_out));
  free(in);
  free(out);
  free(ref_out);
