      if (ix >= radius && ix < (dimx - radius) && iy >= radius &&
          iy < (dimy - radius)) {
        float difference = std::fabs(*reference - *output);
        norm2 += difference * difference;
        if (difference > delta) {
          error = true;
          std::fprintf(fp, " ERROR: (%zu,%zu)\t%e instead of %e (|e|=%e)\n", ix, iy,
                       *output, *reference, difference);
        }
      }

      ++output;
      ++reference;
    }
  }

  if (fp != stderr) std::fclose(fp);
  norm2 = std::sqrt(norm2);
  if (error) std::printf("error (Euclidean norm): %.9e\n", norm2);
  return error;
}

void iso_2dfd_iteration_cpu(float* next, float* prev, float* vel,
                            const float dtDIVdxy, int nRows, int nCols,
                            int nIterations) {
  for (unsigned int k = 0; k < (unsigned int)nIterations; k += 1) {
    for (size_t i = 1; i < (size_t)nRows - HALF_LENGTH; i += 1) {
      for (size_t j = 1; j < (size_t)nCols - HALF_LENGTH; j += 1) {
        size_t gid = j + (i * (size_t)nCols);
        float value = 0.f;
        value += prev[gid + 1] - 2.f * prev[gid] + prev[gid - 1];
        value += prev[gid + nCols] - 2.f * prev[gid] + prev[gid - nCols];
        value *= dtDIVdxy * vel[gid];
        next[gid] = 2.f * prev[gid] - next[gid] + value;
      }
    }

    float* swap = next;
    next = prev;
    prev = swap;
  }
}

__global__ void iso_2dfd_kernel_cuda(float* next, const float* prev,
                                     const float* vel, const float dtDIVdxy,
                                     const size_t nRows, const size_t nCols) {
  size_t gidCol = blockIdx.x * blockDim.x + threadIdx.x;
  size_t gidRow = blockIdx.y * blockDim.y + threadIdx.y;

  if (gidRow < nRows && gidCol < nCols) {
    size_t gid = gidRow * nCols + gidCol;

    if ((gidCol >= HALF_LENGTH && gidCol < nCols - HALF_LENGTH) &&
        (gidRow >= HALF_LENGTH && gidRow < nRows - HALF_LENGTH)) {
      float value = 0.f;
      value += prev[gid + 1] - 2.f * prev[gid] + prev[gid - 1];
      value += prev[gid + nCols] - 2.f * prev[gid] + prev[gid - nCols];
      value *= dtDIVdxy * vel[gid];
      next[gid] = 2.f * prev[gid] - next[gid] + value;
    }
  }
}

void iso_2dfd_kernel(float* next, const float* prev, const float* vel,
                     const float dtDIVdxy, const size_t nRows,
                     const size_t nCols) {
  dim3 block(16, 16);
  dim3 grid((unsigned int)((nCols + block.x - 1) / block.x),
            (unsigned int)((nRows + block.y - 1) / block.y));
  iso_2dfd_kernel_cuda<<<grid, block>>>(next, prev, vel, dtDIVdxy, nRows, nCols);
}

int main(int argc, char* argv[]) {
  float* prev_base;
  float* next_base;
  float* next_cpu;
  float* vel_base;

  bool error = false;

  size_t nRows, nCols;
  unsigned int nIterations;

  try {
    if (argc < 4) throw 1;
    nRows = std::stoull(argv[1]);
    nCols = std::stoull(argv[2]);
    nIterations = (unsigned int)std::stoul(argv[3]);
  } catch (...) {
    usage(argv[0]);
    return 1;
  }

  size_t nsize = nRows * nCols;

  prev_base = new float[nsize];
  next_base = new float[nsize];
  next_cpu = new float[nsize];
  vel_base = new float[nsize];

  float dtDIVdxy = (DT * DT) / (DXY * DXY);

  initialize(prev_base, next_base, vel_base, nRows, nCols);

  std::cout << "Grid Sizes: " << nRows << " " << nCols << std::endl;
  std::cout << "Iterations: " << nIterations << std::endl;
  std::cout << std::endl;

  std::cout << "Computing wavefield in device .." << std::endl;

  float *d_prev = nullptr, *d_next = nullptr, *d_vel = nullptr;
  CHECK_CUDA(cudaMalloc(&d_prev, nsize * sizeof(float)));
  CHECK_CUDA(cudaMalloc(&d_next, nsize * sizeof(float)));
  CHECK_CUDA(cudaMalloc(&d_vel, nsize * sizeof(float)));

  CHECK_CUDA(cudaMemcpy(d_prev, prev_base, nsize * sizeof(float),
                        cudaMemcpyHostToDevice));
  CHECK_CUDA(cudaMemcpy(d_next, next_base, nsize * sizeof(float),
                        cudaMemcpyHostToDevice));
  CHECK_CUDA(cudaMemcpy(d_vel, vel_base, nsize * sizeof(float),
                        cudaMemcpyHostToDevice));

  {
    auto kstart = std::chrono::steady_clock::now();

    for (unsigned int k = 0; k < nIterations; k += 1) {
      iso_2dfd_kernel((k % 2) ? d_prev : d_next, (k % 2) ? d_next : d_prev,
                      d_vel, dtDIVdxy, nRows, nCols);
    }

    CHECK_CUDA(cudaDeviceSynchronize());

    auto kend = std::chrono::steady_clock::now();
    auto ktime =
        std::chrono::duration_cast<std::chrono::nanoseconds>(kend - kstart)
            .count();
    std::cout << "Total kernel execution time " << ktime * 1e-6f << " (ms)\n";
    std::cout << "Average kernel execution time "
              << (ktime * 1e-3f) / nIterations << " (us)\n";
  }

  CHECK_CUDA(cudaMemcpy(next_base, d_next, nsize * sizeof(float),
                        cudaMemcpyDeviceToHost));
  CHECK_CUDA(cudaMemcpy(prev_base, d_prev, nsize * sizeof(float),
                        cudaMemcpyDeviceToHost));

  CHECK_CUDA(cudaFree(d_prev));
  CHECK_CUDA(cudaFree(d_next));
  CHECK_CUDA(cudaFree(d_vel));

  std::ofstream outFile;
  outFile.open("wavefield_snapshot.bin", std::ios::out | std::ios::binary);
  outFile.write(reinterpret_cast<char*>(next_base), nsize * sizeof(float));
  outFile.close();

  std::cout << "Computing wavefield in CPU .." << std::endl;

  initialize(prev_base, next_cpu, vel_base, nRows, nCols);

  auto start = std::chrono::steady_clock::now();
  iso_2dfd_iteration_cpu(next_cpu, prev_base, vel_base, dtDIVdxy, (int)nRows,
                         (int)nCols, (int)nIterations);

  auto end = std::chrono::steady_clock::now();
  auto time =
      std::chrono::duration_cast<std::chrono::milliseconds>(end - start).count();
  std::cout << "CPU time: " << time << " ms" << std::endl;
  std::cout << std::endl;

  std::cout << "Check difference between final wavefields computed in device and host"
            << std::endl;
  error = within_epsilon(next_base, next_cpu, nRows, nCols, HALF_LENGTH, 0.1f);
  std::cout << (error ? "FAIL" : "PASS") << std::endl;

  outFile.open("wavefield_snapshot_cpu.bin", std::ios::out | std::ios::binary);
  outFile.write(reinterpret_cast<char*>(next_cpu), nsize * sizeof(float));
  outFile.close();

  std::cout << "Final wavefields (from device and CPU) written to disk"
            << std::endl;
  std::cout << "Finished.  " << std::endl;

  delete[] prev_base;
  delete[] next_base;
  delete[] next_cpu;
  delete[] vel_base;

  return error ? 1 : 0;
}

